// Current-state snapshots. One row per entity, live-updated.

export interface AgentSessionState {
  entity_id: string;
  retention: "session";
  last_updated: string; // ISO-8601
  // fields tracked:
  // - session_id
  // - started_at
  // - status
}

export interface UserQueryState {
  entity_id: string;
  retention: "session";
  last_updated: string; // ISO-8601
  // fields tracked:
  // - query_id
  // - text
  // - intent
}

// Append-only event ledger. Every state change emits an event.

// event_type: "agent_session.created"
export interface AgentSession.createdEvent {
  event_id: string;
  entity: "agent_session";
  event_type: "agent_session.created";
  at: string; // ISO-8601
  payload: {
    id: string;
    at: datetime;
  };
}

// event_type: "agent_session.updated"
export interface AgentSession.updatedEvent {
  event_id: string;
  entity: "agent_session";
  event_type: "agent_session.updated";
  at: string; // ISO-8601
  payload: {
    id: string;
    changed_fields: array;
    at: datetime;
  };
}

// event_type: "user_query.created"
export interface UserQuery.createdEvent {
  event_id: string;
  entity: "user_query";
  event_type: "user_query.created";
  at: string; // ISO-8601
  payload: {
    id: string;
    at: datetime;
  };
}

// event_type: "user_query.updated"
export interface UserQuery.updatedEvent {
  event_id: string;
  entity: "user_query";
  event_type: "user_query.updated";
  at: string; // ISO-8601
  payload: {
    id: string;
    changed_fields: array;
    at: datetime;
  };
}

// Bounded set of actions the agent may emit.
// The policy engine validates every action before it reaches the outside world.

export type ActionName =
  never; // no actions declared in this workflow

export interface Action {
  name: ActionName;
  args: Record<string, unknown>;
  requires_approval: boolean;
  boundary: "act_on" | "interpret_first";
}

export const ACTION_REGISTRY: Record<string, { purpose: string; requires_approval: boolean }> = {
};

// Outcome feedback loop. Every session closes with an outcome row
// so the world model can learn what happened after each action.

export interface OutcomeRow {
  session_id: string;
  outcome: "success" | "partial" | "fail";
  evidence_refs: string[]; // ids into evidence_refs.json
  cost_usd: number;
  duration_ms: number;
  notes: string; // human / auto-generated post-mortem
  at: string; // ISO-8601
}

